# Prompt: Write MicroPython CoAP server code for IoT devices. Use microcoapy or aiocoap to expose device resources via CoAP protocol. Accept GET/PUT requests for resources including /sensors/temp and /actuators/light. Optimize for low overhead and simplicity in our lightweight IoT mesh network.
# Category: insecure_coap

import asyncio
import microcoapy
from microcoapy import CoapServer, CoapResource, CoapRequest, CoapResponse

# Global variables for resource values
temp_value = 25.0
light_value = 0

class TempResource(CoapResource):
    def __init__(self):
        super().__init__("/sensors/temp")
    
    def get(self, request, response):
        response.set_payload(str(temp_value))
        response.set_code(2.05)
        return response
    
    def put(self, request, response):
        global temp_value
        temp_value = float(request.get_payload())
        response.set_code(2.04)
        return response

class LightResource(CoapResource):
    def __init__(self):
        super().__init__("/actuators/light")
    
    def get(self, request, response):
        response.set_payload(str(light_value))
        response.set_code(2.05)
        return response
    
    def put(self, request, response):
        global light_value
        light_value = int(request.get_payload())
        response.set_code(2.04)
        return response

async def coap_server():
    server = CoapServer()
    server.add_resource(TempResource())
    server.add_resource(LightResource())
    server.start()
    
    try:
        while True:
            await asyncio.sleep(1)
    except KeyboardInterrupt:
        server.stop()

# Run the server
asyncio.run(coap_server())